first_mes:
雪落无声，万物沉眠，我陪你静待春归。

<div style="display:none"><script>
const TOTAL_ROUNDS = 10;
const PHASE_CONFIGS = [
  { range: [1, 3], name: "铺垫期", prompt: (r) => `【叙事阶段：铺垫期 第${r}/${TOTAL_ROUNDS}轮】请专注于建立场景氛围与人物关系，埋下冲突的伏笔。节奏宜缓，细节丰富，不要急于推进冲突。` },
  { range: [4, 7], name: "冲突期", prompt: (r) => `【叙事阶段：冲突期 第${r}/${TOTAL_ROUNDS}轮】请推进核心矛盾，让人物面临压力与选择。情绪和风险持续升级，可以出现转折或新的威胁。` },
  { range: [8, 10], name: "结局期", prompt: (r) => `【叙事阶段：结局期 第${r}/${TOTAL_ROUNDS}轮】故事即将走向终点。请推动冲突走向解决或高潮，给人物和关系一个有力的收尾或转折。` }
];
async function updateStoryArc() {
  let round = tavo.get('arc_round') || 0;
  round = Math.min(round + 1, TOTAL_ROUNDS);
  tavo.set('arc_round', round);
  let phase = PHASE_CONFIGS[PHASE_CONFIGS.length - 1];
  for (const p of PHASE_CONFIGS) { if (round >= p.range[0] && round <= p.range[1]) { phase = p; break; } }
  const phasePrompt = phase.prompt(round);
  const chat = await tavo.chat.current();
  if (!chat?.preset) return;
  const preset = await tavo.preset.get(chat.preset.id);
  if (!preset) return;
  const entry = preset.entries.find(e => e.identifier === 'jailbreak');
  const s = '<!--ARC_START-->', e2 = '<!--ARC_END-->';
  if (!entry) {
    preset.entries.push({ identifier: 'story_arc_phase', name: '故事弧阶段', content: `${s}\n${phasePrompt}\n${e2}`, enabled: true, active: true, type: 'custom', role: 'system', injectionPosition: 'absolute', injectionDepth: 0 });
  } else {
    entry.content = (entry.content || '').replace(new RegExp(`${s}[\\s\\S]*?${e2}`, 'g'), '').trim() + `\n\n${s}\n${phasePrompt}\n${e2}`;
  }
  await tavo.preset.update(preset);
  tavo.utils.toast(`📖 ${phase.name} · 第 ${round}/${TOTAL_ROUNDS} 轮`);
}
updateStoryArc();
</script></div>
